-- ── Pydio Cells ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Open-core, self-hosted enterprise file sharing and document collaboration platform, now integrated into Wire's secure workspace following Wire's 2025 acquisition of Pydio.$q$, short_description),
  pricing_model = COALESCE($q$Open-core: free self-hosted Cells Home edition (AGPLv3) plus paid Connect and Enterprise subscriptions licensed per user per year$q$, pricing_model),
  starting_price = COALESCE($q$Free (Cells Home); paid Connect plans start around EUR 3,280/year for 50 users$q$, starting_price),
  founded_year = COALESCE(2007, founded_year),
  company_size = COALESCE($q$Roughly 11-50 employees (per LinkedIn) prior to being absorbed into Wire's team following the January 2025 acquisition$q$, company_size),
  headquarters = COALESCE($q$Paris, France; now operating as part of Wire, which is headquartered in Berlin, Germany$q$, headquarters),
  languages = ARRAY[$q$English$q$, $q$French$q$, $q$German$q$]::text[],
  seo_title = COALESCE($q$Pydio Cells Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$Pydio Cells is a self-hosted, open-core file sharing and document collaboration platform now part of Wire. Compare pricing, features, and FAQs.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Pydio Cells is a self-hosted, enterprise-grade file sharing and document collaboration platform with roots going back to 2007, when French musician-turned-developer Charles du Jeu created the original project under the name AjaXplorer. As demand for professional support grew, the company Pydio SAS was formally established in Paris in 2012 to commercialize the open-source core, and the product was rebranded from AjaXplorer to Pydio in 2013. The current-generation product, Pydio Cells, is a full rewrite built for scale, offering filesystem and S3-compatible object storage, a built-in user directory, granular sharing controls, online document preview, a REST API with SDKs, WebDAV support, and desktop and mobile sync clients. Pydio has historically claimed over 1 million downloads worldwide and customers in more than 25 countries, positioning Cells as one of the largest open-source enterprise file-sharing platforms. The product follows an open-core model: Cells Home is a free, AGPLv3-licensed download intended for individuals and small-scale evaluation, while Cells Connect (starting around EUR 3,280 per year for 50 users, with volume discounts from 100 users) adds enterprise directory integration (AD/LDAP), single sign-on via OpenID Connect, OAuth2, and SAML/Azure ADFS, white-labeling, and supported cloud images. Cells Enterprise (starting around EUR 4,380 per year for 50 users, roughly EUR 5,980 at 100 users) layers on role- and rule-based access control, multi-factor authentication, exportable audit logs, real-time share auditing, additional cloud storage backends like Google Cloud Storage and Azure Blob Storage, custom versioning policies, and optional OnlyOffice integration for in-browser document editing. In a major development for the company, Berlin-based secure messaging provider Wire announced its acquisition of Pydio on January 14, 2025, with the explicit goal of merging Pydio's Cells document-sharing technology into Wire's encrypted communications platform to create an integrated, security-focused workspace product referred to as 'Wire Cells.' Under this arrangement, Pydio's founder Charles du Jeu described the deal as combining two segment-leading, security-conscious products, and Wire's leadership framed the goal as eliminating the trade-off between strong security and everyday productivity. As of the acquisition, Pydio's technology is being integrated as a component of Wire's broader platform rather than continuing indefinitely as a fully independent standalone product line, although the Pydio brand, website, and Cells product continued to be actively marketed and sold at the time of research. Pydio Cells is typically compared to other self-hosted file-sharing platforms such as Nextcloud and ownCloud, and it is reviewed on third-party software directories including Capterra and GoodFirms. Its core audience is security- and compliance-conscious organizations - particularly in regulated industries or the public sector - that want full control over where their files live, rather than relying on a third-party cloud storage vendor.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '458633b6-d7a2-4972-910e-e20a9a1c4947';

