-- ── Python Environments ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Official Microsoft VS Code extension that unifies Python virtual environment and package management for venv, conda, uv, pyenv, poetry, and pipenv in a single UI.$q$, short_description),
  pricing_model = COALESCE($q$Free - distributed as a free extension on the Visual Studio Code Marketplace$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2024, founded_year),
  company_size = COALESCE($q$Microsoft Corporation has 200,000-plus employees globally; the extension itself is built and maintained by Microsoft's VS Code Python tooling team$q$, company_size),
  headquarters = COALESCE($q$Redmond, Washington, United States (Microsoft Corporation)$q$, headquarters),
  languages = ARRAY[$q$Python$q$]::text[],
  seo_title = COALESCE($q$Python Environments (VS Code) Review 2026: Features and FAQs$q$, seo_title),
  seo_meta_description = COALESCE($q$Python Environments is Microsoft's official VS Code extension for managing Python venv, conda, uv, pyenv, poetry, and pipenv environments. See features and FAQs.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Python Environments (marketplace ID ms-python.vscode-python-envs) is an official Visual Studio Code extension built by Microsoft's Python tooling team to unify Python environment and package management inside the editor. It was first introduced in preview around December 2024 as part of Microsoft's ongoing effort to modernize the Python development experience in VS Code, and after roughly a year in preview - refined through community feedback and real-world usage - it rolled out toward general availability in mid-to-late 2025. The extension consolidates functionality that was previously scattered across the core Python extension into a single, dedicated 'Environments' view in the VS Code Activity Bar, where developers can create, delete, and switch between Python environments and manage installed packages, all regardless of which underlying environment manager they use - venv, conda, uv, pyenv, poetry, or pipenv are all supported through a common interface. A key capability is 'Quick Create,' a one-click flow (the plus button in the Environment Managers view) that builds a new environment using the developer's default manager and the latest available Python version, automatically picking up dependencies declared in a requirements.txt or pyproject.toml file. The extension also introduces native multi-project support: rather than forcing an entire VS Code workspace to share one interpreter, developers can define 'Projects' that assign different Python environments to different folders, which is particularly useful for monorepos, microservices, or codebases that need to test against multiple Python versions simultaneously. Environment assignments are stored portably - the extension records the environment manager type in .vscode/settings.json rather than a hardcoded interpreter path, so configuration travels cleanly across machines, operating systems, and team members. Microsoft has signaled that the broader Python extension is being migrated toward using this dedicated extension by default, controllable via the python.useEnvsExtension setting, with users able to opt in early or have it enabled automatically as rollout progresses. The extension is developed in the open on GitHub under microsoft/vscode-python-environments, where its APIs are documented as still evolving even as the tool approaches general availability, and it is announced and iterated on through Microsoft's regular 'Python in Visual Studio Code' release blog posts on the Microsoft for Python Developers blog. As with all official VS Code extensions from Microsoft, Python Environments is entirely free to install and use, with no paid tiers, since Microsoft's Python tooling is provided at no cost to drive adoption of VS Code and Python more broadly. It is aimed squarely at Python developers who juggle multiple environment managers or multi-root workspaces and want one consistent UI rather than separate, manager-specific command-line workflows.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '1e6c38bd-b82c-4f50-91a4-71da66b398d7';

